// Validate incoming evidence request
const { phase_name, phase_output, success_criteria, client_id, request_id } = $input.first().json.body;

if (!phase_name || !phase_output || !success_criteria) {
  throw new Error('Missing required: phase_name, phase_output, success_criteria');
}

const validation_id = `audit-${request_id || phase_name}-${Date.now()}`;

return [{
  json: {
    validation_id,
    phase_name,
    phase_output: phase_output.slice(0, 5000),
    success_criteria,
    client_id: client_id || 'unknown',
    request_id: request_id || 'unknown',
    received_at: new Date().toISOString()
  }
}];

// Structural validation: check required fields in phase output
const output = JSON.parse($json.phase_output);
const criteria = Array.isArray($json.success_criteria) ? $json.success_criteria : $json.success_criteria.split(',');

const structural_issues = [];

// Check for required sections based on phase
const phase_requirements = {
  'DISCOVER': ['market_opportunity', 'competitive_landscape', 'client_objectives'],
  'STRATEGIZE': ['positioning', 'messaging_pillars', 'channel_mix', 'budget'],
  'SCAFFOLD': ['content_calendar', 'creative_briefs', 'platform_requirements'],
  'BUILD': ['creative_assets', 'seo_optimization', 'paid_media_setup'],
  'HARDEN': ['qa_results', 'ab_tests_config', 'compliance_validation'],
  'LAUNCH': ['audiences_targeted', 'campaigns_live', 'budget_deployed'],
  'OPERATE': ['performance_metrics', 'optimization_recommendations', 'team_briefing']
};

const required = phase_requirements[$json.phase_name] || [];
required.forEach(field => {
  if (!(field in output) || !output[field]) {
    structural_issues.push(`Missing required field: ${field}`);
  }
});

return [{
  json: {
    validation_id: $json.validation_id,
    phase_name: $json.phase_name,
    structural_valid: structural_issues.length === 0,
    structural_issues,
    phase_output: $json.phase_output,
    success_criteria: $json.success_criteria
  }
}];

// Extract validation verdict
const editor_response = $node['Semantic Validation (Editor en Jefe QC)'].json;

let verdict = 'PASS';
let severity = 'low';
let issues = [];

if (editor_response.success === false) {
  verdict = 'FAIL';
  severity = 'critical';
  issues = [editor_response.error || 'Editor validation failed'];
} else {
  verdict = editor_response.verdict || 'PASS';
  severity = editor_response.severity || 'low';
  issues = editor_response.issues || [];
}

return [{
  json: {
    validation_id: $json.validation_id,
    phase_name: $json.phase_name,
    verdict,
    severity,
    structural_issues: $json.structural_issues || [],
    semantic_issues: issues,
    editor_rationale: editor_response.rationale || '',
    all_issues_count: ($json.structural_issues || []).length + issues.length,
    validated_at: new Date().toISOString()
  }
}];
